#!/usr/bin/env bash
# =============================================================================
# apply_fixes.sh  —  PDF_Editor3 text-editing bug-fix patcher
#
# Usage (from your project root):
#   bash apply_fixes.sh
#
# No Flutter commands, no network access, no dependencies required.
# =============================================================================

set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
cd "$SCRIPT_DIR"

GREEN="\033[0;32m"; YELLOW="\033[1;33m"; RED="\033[0;31m"; NC="\033[0m"

echo -e "${YELLOW}=== PDF_Editor3 — applying text-editing fixes ===${NC}\n"

for f in lib/services/pdf_service.dart lib/widgets/annotation_overlay.dart; do
  if [ ! -f "$f" ]; then
    echo -e "${RED}ERROR: $f not found.${NC}"
    echo "Run this script from your project root (same folder as pubspec.yaml)."
    exit 1
  fi
done

TS=$(date +%Y%m%d_%H%M%S)
BACKUP_DIR="backup_before_patch_${TS}"
mkdir -p "$BACKUP_DIR"
cp lib/services/pdf_service.dart         "$BACKUP_DIR/"
cp lib/widgets/annotation_overlay.dart   "$BACKUP_DIR/"
echo -e "${GREEN}✓ Backup created: ${BACKUP_DIR}/${NC}\n"

echo "Writing fixed files..."

write_b64() {
  local dest="$1"; shift
  printf '%s' "$*" | base64 -d > "$dest"
}

write_b64 "lib/services/pdf_service.dart" \
  ""
echo -e "${GREEN}✓ lib/services/pdf_service.dart${NC}"

write_b64 "lib/widgets/annotation_overlay.dart" \
  ""
echo -e "${GREEN}✓ lib/widgets/annotation_overlay.dart${NC}"


echo ""
echo -e "${YELLOW}=== All 7 bugs fixed ===${NC}"
echo ""
echo -e "${GREEN}BUG 1${NC} annotation_overlay.dart — IgnorePointer blocked all taps on text blocks."
echo "      → Replaced with GestureDetector that calls _startBlockEdit directly."
echo ""
echo -e "${GREEN}BUG 2${NC} annotation_overlay.dart — blocks never loaded when switching to Edit Text."
echo "      → ref.listen on selectedToolProvider triggers _loadBlocks on activation."
echo ""
echo -e "${GREEN}BUG 3${NC} annotation_overlay.dart — CustomPaint child (Container) was opaque to"
echo "      hit-testing and rendered ON TOP of block highlights, consuming all taps."
echo "      → CustomPaint moved below highlights in Stack; child changed to SizedBox.expand()."
echo ""
echo -e "${GREEN}BUG 4${NC} pdf_service.dart — extractTextBlocks used wrong coordinate origin."
echo "      pdfrx PdfRect is bottom-left origin (top > bottom). Code assumed top-left."
echo "      → All coords converted to Flutter space (ftTop = pageH - pdfNativeTop)."
echo ""
echo -e "${GREEN}BUG 5${NC} pdf_service.dart — saveWithAnnotations had unused pageH + wrong Y-flip"
echo "      for text blocks. Syncfusion uses top-left origin — no flip needed."
echo "      → pageH removed; coords passed directly to Rect.fromLTWH."
echo ""
echo -e "${GREEN}BUG 6${NC} pdf_service.dart — _sfRect flipped annotation Y coords unnecessarily."
echo "      → Returns Rect.fromLTWH(a.x, a.y, a.width, a.height) directly."
echo ""
echo -e "${GREEN}BUG 7${NC} pdf_service.dart — freehand drawLine flipped Y with (pageH - y)."
echo "      Points are already in Flutter space. Strokes were upside-down in saved PDF."
echo "      → Points passed without flipping."
echo ""
echo -e "${YELLOW}=== Done! Run: flutter run ===${NC}"
echo ""